UPDATE market_trading_session
SET session_name = #{sessionName}, start_time = #{startTime}, end_time = #{endTime},
    is_auction = #{isAuction}, sort_order = #{sortOrder}, enabled = #{enabled}
WHERE id = #{id}

mapper.select:
SELECT 
FROM market_trading_session
WHERE market_code = #{marketCode}
AND enabled = #{enabled}
ORDER BY sort_order ASC
